using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Course> Courses = new()
    {
        new Course { Id = 1, Code = "CS101", Title = "Introduction to Computer Science", Description = "Foundational course covering algorithms, data structures, and computational thinking. Students learn problem-solving techniques and basic programming concepts.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentCode = "CS", DepartmentName = "Computer Science", IsFeatured = true, Instructor = new Instructor { Name = "Dr. Sarah Chen", Title = "Associate Professor", Bio = "Dr. Chen specializes in algorithms and has published over 40 papers on computational complexity. She received her PhD from MIT and has been teaching for 15 years.", Email = "s.chen@university.edu" } },
        new Course { Id = 2, Code = "CS301", Title = "Database Systems", Description = "Design and implementation of relational databases. Covers SQL, normalization, transaction processing, and modern NoSQL approaches.", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", DepartmentCode = "CS", DepartmentName = "Computer Science", IsFeatured = true, Instructor = new Instructor { Name = "Dr. Michael Torres", Title = "Professor", Bio = "Dr. Torres spent 10 years in industry at Oracle before joining academia. His research focuses on distributed database systems and query optimization.", Email = "m.torres@university.edu" } },
        new Course { Id = 3, Code = "CS205", Title = "Software Engineering", Description = "Principles of software design, development methodologies, version control, testing, and team collaboration. Includes a semester-long group project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", DepartmentCode = "CS", DepartmentName = "Computer Science", Instructor = new Instructor { Name = "Dr. Lisa Park", Title = "Assistant Professor", Bio = "Dr. Park brings industry experience from Google and Microsoft. Her research focuses on agile methodologies and developer productivity.", Email = "l.park@university.edu" } },
        new Course { Id = 4, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to data science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentCode = "MATH", DepartmentName = "Mathematics", IsFeatured = true, Instructor = new Instructor { Name = "Dr. James Wright", Title = "Professor", Bio = "Dr. Wright is a recipient of the University Teaching Excellence Award. He has authored three textbooks on linear algebra and its applications.", Email = "j.wright@university.edu" } },
        new Course { Id = 5, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Tue/Thu 8:00–9:15 AM", DepartmentCode = "MATH", DepartmentName = "Mathematics", Instructor = new Instructor { Name = "Dr. Emily Ross", Title = "Associate Professor", Bio = "Dr. Ross completed her doctorate at Princeton and specializes in mathematical analysis. She is passionate about making calculus accessible to all students.", Email = "e.ross@university.edu" } },
        new Course { Id = 6, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Lecture and laboratory components cover Newtonian physics with calculus-based problem solving.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:50 PM", DepartmentCode = "PHYS", DepartmentName = "Physics", Instructor = new Instructor { Name = "Dr. Robert Kim", Title = "Professor", Bio = "Dr. Kim's research in experimental physics has been published in Nature and Physical Review Letters. He emphasizes hands-on learning.", Email = "r.kim@university.edu" } },
        new Course { Id = 7, Code = "PHYS220", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, hydrogen atom, spin, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", DepartmentCode = "PHYS", DepartmentName = "Physics", IsFeatured = true, Instructor = new Instructor { Name = "Dr. Anna Petrov", Title = "Associate Professor", Bio = "Dr. Petrov is a theoretical physicist whose work on quantum information has earned international recognition. She previously held a research position at CERN.", Email = "a.petrov@university.edu" } },
        new Course { Id = 8, Code = "ENG110", Title = "Academic Writing", Description = "Develop critical reading and writing skills for university-level work. Focus on argumentation, research methods, and clear prose.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", DepartmentCode = "ENG", DepartmentName = "English", Instructor = new Instructor { Name = "Prof. David Grant", Title = "Senior Lecturer", Bio = "Prof. Grant is an award-winning author and writing instructor with 20 years of experience helping students find their academic voice.", Email = "d.grant@university.edu" } },
        new Course { Id = 9, Code = "ENG250", Title = "World Literature", Description = "Survey of major literary works from diverse cultures and time periods. Explores themes of identity, power, and the human condition.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", DepartmentCode = "ENG", DepartmentName = "English", Instructor = new Instructor { Name = "Dr. Maria Santos", Title = "Associate Professor", Bio = "Dr. Santos specializes in comparative literature with a focus on postcolonial narratives. She has translated works from five languages.", Email = "m.santos@university.edu" } },
        new Course { Id = 10, Code = "HIST101", Title = "World History to 1500", Description = "Survey of human civilizations from prehistory through the medieval period. Covers political, economic, social, and cultural developments.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentCode = "HIST", DepartmentName = "History", Instructor = new Instructor { Name = "Dr. Thomas Blake", Title = "Professor", Bio = "Dr. Blake is an archaeologist and historian whose fieldwork spans three continents. He brings primary source analysis into every lecture.", Email = "t.blake@university.edu" } },
    };

    public Task<List<Course>> GetCoursesAsync(string? searchTerm = null, string? departmentCode = null)
    {
        var query = Courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(departmentCode))
            query = query.Where(c => c.DepartmentCode == departmentCode);

        if (!string.IsNullOrWhiteSpace(searchTerm))
            query = query.Where(c =>
                c.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));

        return Task.FromResult(query.ToList());
    }

    public Task<List<Course>> GetFeaturedCoursesAsync()
    {
        return Task.FromResult(Courses.Where(c => c.IsFeatured).ToList());
    }

    public Task<Course?> GetCourseByIdAsync(int id)
    {
        return Task.FromResult(Courses.FirstOrDefault(c => c.Id == id));
    }

    public Task<List<Department>> GetDepartmentsAsync()
    {
        var departments = Courses
            .GroupBy(c => new { c.DepartmentCode, c.DepartmentName })
            .Select(g => new Department
            {
                Code = g.Key.DepartmentCode,
                Name = g.Key.DepartmentName,
                CourseCount = g.Count()
            })
            .OrderBy(d => d.Name)
            .ToList();

        return Task.FromResult(departments);
    }

    public Task<bool> SubmitEnrollmentRequestAsync(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return Task.FromResult(true);
    }
}

