@using UniversityCourseCatalog.Models

<div class="course-filters">
    <input type="text" placeholder="Search courses, codes, or instructors..."
           @bind="SearchTerm" @bind:event="oninput" @bind:after="OnFilterChanged" />

    <select @bind="SelectedDepartment" @bind:after="OnFilterChanged">
        <option value="">All Departments</option>
        @foreach (var dept in Departments)
        {
            <option value="@dept.Code">@dept.Name</option>
        }
    </select>
</div>

@code {
    [Parameter] public List<Department> Departments { get; set; } = new();
    [Parameter] public EventCallback<(string? Search, string? Department)> OnFiltersChanged { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private string SelectedDepartment { get; set; } = string.Empty;

    private async Task OnFilterChanged()
    {
        var dept = string.IsNullOrEmpty(SelectedDepartment) ? null : SelectedDepartment;
        var search = string.IsNullOrEmpty(SearchTerm) ? null : SearchTerm;
        await OnFiltersChanged.InvokeAsync((search, dept));
    }
}

