arguments.file_text:
@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and find the right courses for your academic journey.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="featured-section">
    <h2>Featured Courses</h2>
    @if (featuredCourses is not null)
    {
        <div class="course-grid">
            @foreach (var course in featuredCourses)
            {
                <CourseCard Course="course" />
            }
        </div>
    }
</section>

<section class="departments-section">
    <h2>Departments</h2>
    @if (departments is not null)
    {
        <div class="department-grid">
            @foreach (var dept in departments)
            {
                <a href="/courses?department=@dept.Code" class="department-link">
                    <span class="dept-name">@dept.Name</span>
                    <span class="dept-count">@dept.CourseCount courses</span>
                </a>
            }
        </div>
    }
</section>

@code {
    private List<Course>? featuredCourses;
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        departments = await CatalogService.GetDepartmentsAsync();
    }
}

.hero {
    text-align: center;
    padding: 3rem 1rem;
    background: linear-gradient(135deg, #1a56db, #3b82f6);
    color: #fff;
    border-radius: 12px;
    margin-bottom: 2.5rem;
}

.hero h1 {
    font-size: 2.2rem;
    margin: 0 0 0.75rem;
}

.hero p {
    font-size: 1.1rem;
    opacity: 0.9;
    margin: 0 0 1.5rem;
}

.btn-primary {
    display: inline-block;
    background: #fff;
    color: #1a56db;
    padding: 0.7rem 1.5rem;
    border-radius: 6px;
    text-decoration: none;
    font-weight: 600;
    transition: background 0.2s;
}

.btn-primary:hover {
    background: #e8f0fe;
}

.featured-section,
.departments-section {
    margin-bottom: 2.5rem;
}

.featured-section h2,
.departments-section h2 {
    font-size: 1.5rem;
    margin-bottom: 1rem;
    color: #1f2937;
}

.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.25rem;
}

.department-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.department-link {
    display: flex;
    flex-direction: column;
    padding: 1.25rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    text-decoration: none;
    color: #1f2937;
    transition: border-color 0.2s, box-shadow 0.2s;
}

.department-link:hover {
    border-color: #1a56db;
    box-shadow: 0 2px 8px rgba(26, 86, 219, 0.1);
}

.dept-name {
    font-weight: 600;
    font-size: 1.05rem;
}

.dept-count {
    color: #6b7280;
    font-size: 0.85rem;
    margin-top: 0.25rem;
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<CourseFilters Departments="departments" OnFiltersChanged="HandleFiltersChanged" />

@if (courses is null)
{
    <p>Loading courses...</p>
}
else if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <p class="results-count">@courses.Count course(s) found</p>
    <div class="course-grid">
        @foreach (var course in courses)
        {
            <CourseCard Course="course" />
        }
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "department")]
    public string? DepartmentFilter { get; set; }

    private List<Course>? courses;
    private List<Department> departments = new();

    protected override async Task OnInitializedAsync()
    {
        departments = await CatalogService.GetDepartmentsAsync();
        courses = await CatalogService.GetCoursesAsync(departmentCode: DepartmentFilter);
    }

    private async Task HandleFiltersChanged((string? Search, string? Department) filters)
    {
        courses = await CatalogService.GetCoursesAsync(filters.Search, filters.Department);
    }
}

h1 {
    margin-bottom: 1.5rem;
    color: #1f2937;
}

.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.25rem;
}

.no-results {
    color: #6b7280;
    font-style: italic;
    padding: 2rem 0;
}

.results-count {
    color: #6b7280;
    font-size: 0.9rem;
    margin-bottom: 1rem;
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Detail") - University Course Catalog</PageTitle>

@if (course is null)
{
    <p>Loading course details...</p>
}
else
{
    <nav class="breadcrumb">
        <a href="/courses">← Back to Courses</a>
    </nav>

    <div class="course-detail">
        <div class="detail-header">
            <span class="course-code">@course.Code</span>
            <span class="department-tag">@course.DepartmentName</span>
        </div>

        <h1>@course.Title</h1>

        <div class="detail-meta">
            <div class="meta-item">
                <strong>Credits:</strong> @course.Credits
            </div>
            <div class="meta-item">
                <strong>Schedule:</strong> @course.Schedule
            </div>
            <div class="meta-item">
                <strong>Instructor:</strong> @course.Instructor.Name
            </div>
        </div>

        <div class="description">
            <h2>Course Description</h2>
            <p>@course.Description</p>
        </div>

        <InstructorBio Instructor="course.Instructor" />

        <div class="enroll-cta">
            <a href="/enroll?courseId=@course.Id" class="btn-enroll">Request Enrollment</a>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override async Task OnInitializedAsync()
    {
        course = await CatalogService.GetCourseByIdAsync(Id);
    }
}

.breadcrumb {
    margin-bottom: 1.5rem;
}

.breadcrumb a {
    color: #1a56db;
    text-decoration: none;
    font-size: 0.9rem;
}

.breadcrumb a:hover {
    text-decoration: underline;
}

.course-detail {
    max-width: 800px;
}

.detail-header {
    display: flex;
    gap: 0.75rem;
    align-items: center;
    margin-bottom: 0.5rem;
}

.course-code {
    font-weight: 600;
    color: #1a56db;
    font-size: 1rem;
}

.department-tag {
    background: #e8f0fe;
    color: #1a56db;
    padding: 0.2rem 0.8rem;
    border-radius: 12px;
    font-size: 0.8rem;
}

h1 {
    font-size: 1.8rem;
    color: #1f2937;
    margin: 0.5rem 0 1.5rem;
}

.detail-meta {
    display: flex;
    flex-wrap: wrap;
    gap: 1.5rem;
    margin-bottom: 2rem;
    padding: 1rem 1.25rem;
    background: #f9fafb;
    border-radius: 8px;
}

.meta-item {
    font-size: 0.95rem;
    color: #374151;
}

.meta-item strong {
    color: #1f2937;
}

.description h2 {
    font-size: 1.2rem;
    margin: 0 0 0.75rem;
    color: #1f2937;
}

.description p {
    line-height: 1.7;
    color: #374151;
}

.enroll-cta {
    margin-top: 2rem;
}

.btn-enroll {
    display: inline-block;
    background: #1a56db;
    color: #fff;
    padding: 0.75rem 1.5rem;
    border-radius: 6px;
    text-decoration: none;
    font-weight: 600;
    transition: background 0.2s;
}

.btn-enroll:hover {
    background: #1648b8;
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Request Submitted!</h2>
        <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
        <a href="/courses">Browse more courses</a>
    </div>
}
else
{
    <div class="enroll-form-container">
        <p class="form-intro">Complete the form below to request enrollment in a course.</p>

        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />

            <div class="form-group">
                <label for="studentName">Full Name</label>
                <InputText id="studentName" @bind-Value="model.StudentName" placeholder="Enter your full name" />
                <ValidationMessage For="() => model.StudentName" />
            </div>

            <div class="form-group">
                <label for="studentId">Student ID</label>
                <InputText id="studentId" @bind-Value="model.StudentId" placeholder="e.g., STU-12345" />
                <ValidationMessage For="() => model.StudentId" />
            </div>

            <div class="form-group">
                <label for="courseSelect">Course</label>
                <InputSelect id="courseSelect" @bind-Value="model.CourseId">
                    <option value="0">-- Select a course --</option>
                    @if (courses is not null)
                    {
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code - @course.Title</option>
                        }
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" />
            </div>

            <button type="submit" class="btn-submit">Submit Request</button>
        </EditForm>
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private EnrollmentFormModel model = new();
    private List<Course>? courses;
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        courses = await CatalogService.GetCoursesAsync();
        if (PreselectedCourseId.HasValue)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private async Task HandleSubmit()
    {
        var request = new EnrollmentRequest
        {
            StudentName = model.StudentName,
            StudentId = model.StudentId,
            CourseId = model.CourseId
        };
        await CatalogService.SubmitEnrollmentRequestAsync(request);
        submitted = true;
    }

    private class EnrollmentFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Name is required.")]
        public string StudentName { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Student ID is required.")]
        public string StudentId { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
        public int CourseId { get; set; }
    }
}

