@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="hero">
    <h1>University Course Catalog</h1>
    <p>Explore our departments and find the right courses for your academic journey.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</div>

<section class="featured-section">
    <h2>Featured Courses</h2>
    @if (featuredCourses is not null)
    {
        <div class="course-grid">
            @foreach (var course in featuredCourses)
            {
                <CourseCard Course="course" />
            }
        </div>
    }
</section>

<section class="departments-section">
    <h2>Departments</h2>
    @if (departments is not null)
    {
        <div class="department-grid">
            @foreach (var dept in departments)
            {
                <a href="/courses?department=@dept.Code" class="department-link">
                    <span class="dept-name">@dept.Name</span>
                    <span class="dept-count">@dept.CourseCount courses</span>
                </a>
            }
        </div>
    }
</section>

@code {
    private List<Course>? featuredCourses;
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await CatalogService.GetFeaturedCoursesAsync();
        departments = await CatalogService.GetDepartmentsAsync();
    }
}

.hero {
    text-align: center;
    padding: 3rem 1rem;
    background: linear-gradient(135deg, #1a56db, #3b82f6);
    color: #fff;
    border-radius: 12px;
    margin-bottom: 2.5rem;
}

.hero h1 {
    font-size: 2.2rem;
    margin: 0 0 0.75rem;
}

.hero p {
    font-size: 1.1rem;
    opacity: 0.9;
    margin: 0 0 1.5rem;
}

.btn-primary {
    display: inline-block;
    background: #fff;
    color: #1a56db;
    padding: 0.7rem 1.5rem;
    border-radius: 6px;
    text-decoration: none;
    font-weight: 600;
    transition: background 0.2s;
}

.btn-primary:hover {
    background: #e8f0fe;
}

.featured-section,
.departments-section {
    margin-bottom: 2.5rem;
}

.featured-section h2,
.departments-section h2 {
    font-size: 1.5rem;
    margin-bottom: 1rem;
    color: #1f2937;
}

.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.25rem;
}

.department-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
}

.department-link {
    display: flex;
    flex-direction: column;
    padding: 1.25rem;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    text-decoration: none;
    color: #1f2937;
    transition: border-color 0.2s, box-shadow 0.2s;
}

.department-link:hover {
    border-color: #1a56db;
    box-shadow: 0 2px 8px rgba(26, 86, 219, 0.1);
}

.dept-name {
    font-weight: 600;
    font-size: 1.05rem;
}

.dept-count {
    color: #6b7280;
    font-size: 0.85rem;
    margin-top: 0.25rem;
}

