@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<CourseFilters Departments="departments" OnFiltersChanged="HandleFiltersChanged" />

@if (courses is null)
{
    <p>Loading courses...</p>
}
else if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <p class="results-count">@courses.Count course(s) found</p>
    <div class="course-grid">
        @foreach (var course in courses)
        {
            <CourseCard Course="course" />
        }
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "department")]
    public string? DepartmentFilter { get; set; }

    private List<Course>? courses;
    private List<Department> departments = new();

    protected override async Task OnInitializedAsync()
    {
        departments = await CatalogService.GetDepartmentsAsync();
        courses = await CatalogService.GetCoursesAsync(departmentCode: DepartmentFilter);
    }

    private async Task HandleFiltersChanged((string? Search, string? Department) filters)
    {
        courses = await CatalogService.GetCoursesAsync(filters.Search, filters.Department);
    }
}

