toolArgs.file_text:
@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Detail") - University Course Catalog</PageTitle>

@if (course is null)
{
    <p>Loading course details...</p>
}
else
{
    <nav class="breadcrumb">
        <a href="/courses">← Back to Courses</a>
    </nav>

    <div class="course-detail">
        <div class="detail-header">
            <span class="course-code">@course.Code</span>
            <span class="department-tag">@course.DepartmentName</span>
        </div>

        <h1>@course.Title</h1>

        <div class="detail-meta">
            <div class="meta-item">
                <strong>Credits:</strong> @course.Credits
            </div>
            <div class="meta-item">
                <strong>Schedule:</strong> @course.Schedule
            </div>
            <div class="meta-item">
                <strong>Instructor:</strong> @course.Instructor.Name
            </div>
        </div>

        <div class="description">
            <h2>Course Description</h2>
            <p>@course.Description</p>
        </div>

        <InstructorBio Instructor="course.Instructor" />

        <div class="enroll-cta">
            <a href="/enroll?courseId=@course.Id" class="btn-enroll">Request Enrollment</a>
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? course;

    protected override async Task OnInitializedAsync()
    {
        course = await CatalogService.GetCourseByIdAsync(Id);
    }
}

