toolArgs.file_text:
@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request - University Course Catalog</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>Request Submitted!</h2>
        <p>Your enrollment request has been received. You will be notified once it has been processed.</p>
        <a href="/courses">Browse more courses</a>
    </div>
}
else
{
    <div class="enroll-form-container">
        <p class="form-intro">Complete the form below to request enrollment in a course.</p>

        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />

            <div class="form-group">
                <label for="studentName">Full Name</label>
                <InputText id="studentName" @bind-Value="model.StudentName" placeholder="Enter your full name" />
                <ValidationMessage For="() => model.StudentName" />
            </div>

            <div class="form-group">
                <label for="studentId">Student ID</label>
                <InputText id="studentId" @bind-Value="model.StudentId" placeholder="e.g., STU-12345" />
                <ValidationMessage For="() => model.StudentId" />
            </div>

            <div class="form-group">
                <label for="courseSelect">Course</label>
                <InputSelect id="courseSelect" @bind-Value="model.CourseId">
                    <option value="0">-- Select a course --</option>
                    @if (courses is not null)
                    {
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.Code - @course.Title</option>
                        }
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" />
            </div>

            <button type="submit" class="btn-submit">Submit Request</button>
        </EditForm>
    </div>
}

@code {
    [SupplyParameterFromQuery(Name = "courseId")]
    public int? PreselectedCourseId { get; set; }

    private EnrollmentFormModel model = new();
    private List<Course>? courses;
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        courses = await CatalogService.GetCoursesAsync();
        if (PreselectedCourseId.HasValue)
        {
            model.CourseId = PreselectedCourseId.Value;
        }
    }

    private async Task HandleSubmit()
    {
        var request = new EnrollmentRequest
        {
            StudentName = model.StudentName,
            StudentId = model.StudentId,
            CourseId = model.CourseId
        };
        await CatalogService.SubmitEnrollmentRequestAsync(request);
        submitted = true;
    }

    private class EnrollmentFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Name is required.")]
        public string StudentName { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Student ID is required.")]
        public string StudentId { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
        public int CourseId { get; set; }
    }
}

h1 {
    margin-bottom: 1.5rem;
    color: #1f2937;
}

.form-intro {
    color: #6b7280;
    margin-bottom: 1.5rem;
}

.enroll-form-container {
    max-width: 500px;
}

.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.4rem;
    color: #374151;
    font-size: 0.95rem;
}

.form-group input,
.form-group select {
    width: 100%;
