    font-size: 0.95rem;
    box-sizing: border-box;
}

.form-group input:focus,
.form-group select:focus {
    outline: none;
    border-color: #1a56db;
    box-shadow: 0 0 0 2px rgba(26, 86, 219, 0.15);
}

.validation-message {
    color: #dc2626;
    font-size: 0.8rem;
    margin-top: 0.3rem;
}

